import{_ as e,o as r,c as a,a0 as i}from"./chunks/framework.NWv86GGy.js";const u=JSON.parse('{"title":"New Zealand — Country Profile","description":"Comprehensive guide to New Zealand for transgender relocation: legal recognition, healthcare, cost of living, visa pathways, community, and risks.","frontmatter":{"layout":"doc","title":"New Zealand — Country Profile","description":"Comprehensive guide to New Zealand for transgender relocation: legal recognition, healthcare, cost of living, visa pathways, community, and risks."},"headers":[],"relativePath":"countries/new-zealand/index.md","filePath":"countries/new-zealand/index.md","lastUpdated":1780601195000}'),n={name:"countries/new-zealand/index.md"};function o(s,t,l,d,c,g){return r(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="🇳🇿-new-zealand" tabindex="-1"><span style="color:#00247d;">🇳🇿 New Zealand</span> <a class="header-anchor" href="#🇳🇿-new-zealand" aria-label="Permalink to &quot;&lt;span style=&quot;color: #00247d;&quot;&gt;🇳🇿 New Zealand&lt;/span&gt;&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Field</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Capital</strong></td><td>Wellington</td></tr><tr><td><strong>Population</strong></td><td>~5.1 million</td></tr><tr><td><strong>Language</strong></td><td>English, Māori, NZ Sign Language</td></tr><tr><td><strong>Currency</strong></td><td>New Zealand Dollar (NZD)</td></tr><tr><td><strong>Equaldex Score</strong></td><td>84</td></tr><tr><td><strong>Trans-Specific Rating</strong></td><td>5/5</td></tr><tr><td><strong>Last Verified</strong></td><td>June 2026</td></tr></tbody></table><h2 id="legal-overview" tabindex="-1">Legal Overview <a class="header-anchor" href="#legal-overview" aria-label="Permalink to &quot;Legal Overview&quot;">​</a></h2><ul><li><strong>Gender Recognition:</strong> Self-ID since 2021 (Births, Deaths, Marriages, and Relationships Registration Act). Adults can change legal gender by statutory declaration. No medical requirements, no surgery, no therapy, no court order.</li><li><strong>Anti-Discrimination Law:</strong> Comprehensive under the Human Rights Act 1993, explicitly including gender identity.</li><li><strong>Hate Crime Laws:</strong> Gender identity is a protected category in sentencing.</li><li><strong>Same-Sex Marriage:</strong> Legal since 2013.</li><li><strong>Conversion Therapy:</strong> Banned (2022, one of the first countries to do so).</li></ul><h3 id="key-laws" tabindex="-1">Key Laws <a class="header-anchor" href="#key-laws" aria-label="Permalink to &quot;Key Laws&quot;">​</a></h3><ul><li>Births, Deaths, Marriages, and Relationships Registration Act (2021)</li><li>Human Rights Act 1993 (amended to include gender identity)</li><li>Conversion Therapy Prohibition Act (2022)</li></ul><h2 id="healthcare-reality" tabindex="-1">Healthcare Reality <a class="header-anchor" href="#healthcare-reality" aria-label="Permalink to &quot;Healthcare Reality&quot;">​</a></h2><ul><li><strong>HRT Access:</strong> Informed consent is widely available. Many GPs prescribe HRT directly. Dedicated clinics like the Gender Affirming Service (Auckland) handle complex cases.</li><li><strong>HRT Cost:</strong> NZD 5–15 per prescription (publicly subsidised). Private: NZD 30–60/month.</li><li><strong>Wait Times:</strong> 2–6 weeks for GP appointment. Specialist endocrinology: 1–3 months.</li><li><strong>Surgery:</strong> Public funding available but wait times are long (1–3 years). Private options exist (NZD 15,000–30,000).</li></ul><h3 id="key-resources" tabindex="-1">Key Resources <a class="header-anchor" href="#key-resources" aria-label="Permalink to &quot;Key Resources&quot;">​</a></h3><ul><li><strong>Gender Minorities Aotearoa:</strong> The national trans organisation</li><li><strong>OUTLine NZ:</strong> LGBTQ+ support line</li></ul><h2 id="where-to-live" tabindex="-1">Where to Live <a class="header-anchor" href="#where-to-live" aria-label="Permalink to &quot;Where to Live&quot;">​</a></h2><ul><li><strong>Auckland:</strong> Largest trans community. Most diverse and progressive. Very expensive (1-bedroom: NZD 1,800–2,600/month).</li><li><strong>Wellington:</strong> Strong trans community. Smaller, more affordable. 1-bedroom: NZD 1,500–2,200/month.</li><li><strong>Christchurch:</strong> Smaller community. More conservative feel. Cheaper. 1-bedroom: NZD 1,200–1,800/month.</li><li><strong>Dunedin:</strong> Very small community. Student city.</li></ul><p><strong>Monthly budget (1 person):</strong> NZD 3,000–5,000 (≈ €1,700–2,800).</p><h2 id="visa-pathways" tabindex="-1">Visa Pathways <a class="header-anchor" href="#visa-pathways" aria-label="Permalink to &quot;Visa Pathways&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Income Req.</th><th>Processing</th><th>Leads to PR?</th></tr></thead><tbody><tr><td>Green List Work Visa</td><td>Job in eligible occupation</td><td>1–6 months</td><td>Yes (fast track)</td></tr><tr><td>Working Holiday Visa</td><td>Varies by country</td><td>1–3 months</td><td>No</td></tr><tr><td>Accredited Employer Visa</td><td>Job offer required</td><td>1–4 months</td><td>Yes</td></tr><tr><td>Student Visa</td><td>Proof of funds</td><td>1–3 months</td><td>Yes (post-study)</td></tr></tbody></table><h2 id="known-risks" tabindex="-1">Known Risks <a class="header-anchor" href="#known-risks" aria-label="Permalink to &quot;Known Risks&quot;">​</a></h2><ol><li><strong>Extreme remoteness</strong> — expensive and time-consuming to travel anywhere</li><li><strong>Very high cost of living</strong> — Auckland and Wellington comparable to London</li><li><strong>Housing crisis</strong> in major cities</li><li><strong>Small job market</strong> outside skilled professions</li><li><strong>Distance from support networks</strong> if you are from Europe or the Americas</li></ol><p><em>Sources: Gender Minorities Aotearoa, Human Rights Commission NZ, TGEU, Equaldex. Last verified: June 2026.</em></p>',18)])])}const m=e(n,[["render",o]]);export{u as __pageData,m as default};
